repl("Inspecting CryptPad DOM structure", "const domBriefCp1 = await page.evaluate(() => {
  function walk(node, depth=0) {
    if (depth>3) return '';
    let s = '';
    for (const el of Array.from(node.children||[]).slice(0,20)) {
      s += ' '.repeat(depth*2)+el.tagName.toLowerCase()+'#'+(el.id||'')+'.'+(el.className||'')+' role='+el.getAttribute('role')+' aria='+el.getAttribute('aria-label')+' text='+((el.innerText||'').slice(0,50))+'\n';
      if (el.shadowRoot) s += ' '.repeat(depth*2)+' SHADOW\n'+walk(el.shadowRoot, depth+1);
      s += walk(el, depth+1);
    }
    return s;
  }
  return walk(document.body);
});
console.log(domBriefCp1);")

